const typeId = query.type_id;

const response = await this.helpers.httpRequest({
  method: 'GET',
  url: 'https://esi.evetech.net/latest/markets/10000002/orders/',
  qs: { datasource: 'tranquility', order_type: 'all', type_id: typeId },
  json: true
});

const sellOrders = response.filter(o => o.is_buy_order === false);
if (sellOrders.length === 0) {
  return 'Нет ордеров на продажу для этого предмета.';
}

const bestPrice = Math.min(...sellOrders.map(o => o.price));
return `Лучшая цена продажи: ${bestPrice} ISK`;
